# ✅ Sudoku: Fill grid with constraints (rows, cols, 3×3 boxes)
def solve_sudoku(grid):
    def is_safe(row, col, num):
        # Check row
        for j in range(9):
            if grid[row][j] == num:
                return False
        # Check column
        for i in range(9):
            if grid[i][col] == num:
                return False
        # Check 3×3 box
        box_row, box_col = 3 * (row // 3), 3 * (col // 3)
        for i in range(box_row, box_row + 3):
            for j in range(box_col, box_col + 3):
                if grid[i][j] == num:
                    return False
        return True  # ✅ Safe [web:230]

    def backtrack():
        for row in range(9):
            for col in range(9):
                if grid[row][col] == 0:  # ✅ Empty cell
                    for num in range(1, 10):  # ✅ Try 1-9
                        if is_safe(row, col, num):  # ✅ Prune invalid
                            grid[row][col] = num  # ✅ Choose
                            if backtrack():  # ✅ Explore
                                return True
                            grid[row][col] = 0  # ✅ Backtrack (undo) [web:230]
                    return False  # ❌ No valid num
        return True  # ✅ All filled

    backtrack()
    return grid  # ✅ Solved [web:230]
